patch:
diff --git a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
index a88f8f19f852..6f62f69445c6 100644
--- a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
+++ b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
@@ -604,6 +604,13 @@ APInt ConstantOffsetExtractor::find(Value *V, bool SignExtended,
     else if (BO->getOpcode() == Instruction::Xor)
       ConstantOffset = extractDisjointBitsFromXor(BO);
   } else if (isa<TruncInst>(V)) {
+    // For TruncInst with nuw or nsw, we cannot trace through it because
+    // distributing trunc with flags changes poison semantics.
+    if (cast<TruncInst>(V)->hasNoUnsignedWrap() ||
+        cast<TruncInst>(V)->hasNoSignedWrap()) {
+      // Cannot trace through this trunc; treat it as a leaf.
+      return APInt(BitWidth, 0);
+    }
     ConstantOffset =
         find(U->getOperand(0), SignExtended, ZeroExtended, NonNegative)
             .trunc(BitWidth);
@@ -675,6 +682,21 @@ ConstantOffsetExtractor::distributeExtsAndCloneChain(unsigned ChainIndex) {
     assert(
         (isa<SExtInst>(Cast) || isa<ZExtInst>(Cast) || isa<TruncInst>(Cast)) &&
         "Only following instructions can be traced: sext, zext & trunc");
+    // For TruncInst with nuw or nsw, we cannot distribute it through addition
+    // because distributing trunc with flags changes poison semantics.
+    if (auto *Trunc = dyn_cast<TruncInst>(Cast)) {
+      if (Trunc->hasNoUnsignedWrap() || Trunc->hasNoSignedWrap()) {
+        // Cannot distribute this trunc; treat it as a regular node.
+        Value *NextInChain = distributeExtsAndCloneChain(ChainIndex - 1);
+        // Clone the trunc with the same flags.
+        TruncInst *NewTrunc = new TruncInst(NextInChain, Trunc->getDestTy(),
+                                            Trunc->getName(), IP);
+        NewTrunc->setHasNoUnsignedWrap(Trunc->hasNoUnsignedWrap());
+        NewTrunc->setHasNoSignedWrap(Trunc->hasNoSignedWrap());
+        return UserChain[ChainIndex] = NewTrunc;
+      }
+    }
+    // For sext/zext and trunc without flags, we can distribute them.
     ExtInsts.push_back(Cast);
     UserChain[ChainIndex] = nullptr;
     return distributeExtsAndCloneChain(ChainIndex - 1);
@@ -704,6 +726,11 @@ Value *ConstantOffsetExtractor::removeConstOffset(unsigned ChainIndex) {
     return ConstantInt::getNullValue(UserChain[ChainIndex]->getType());
   }

+  if (!isa<BinaryOperator>(UserChain[ChainIndex])) {
+    // This could be a TruncInst that we didn't distribute.
+    // Return it as is.
+    return UserChain[ChainIndex];
+  }
   BinaryOperator *BO = cast<BinaryOperator>(UserChain[ChainIndex]);
   assert((BO->use_empty() || BO->hasOneUse()) &&
          "distributeExtsAndCloneChain clones each BinaryOperator in "

